const FLASHCARDS = {
  c1: [
    { term: 'Strategy', def: `A long-term plan to reach a particular goal; for businesses, the goal is to maximize NPV.`, cls: 'Class 1 · Foundations' },
    { term: 'Corporate Strategy', def: `Highest-level strategy defining which industries the organization will be active in.`, cls: 'Class 1 · Foundations' },
    { term: 'Business Strategy', def: `Strategy formulated by a business unit to seek favorable competitive position; characterized by Price, Quality, Responsiveness, Variety.`, cls: 'Class 1 · Foundations' },
    { term: 'Operations Strategy (OS)', def: `A long-term plan for developing resources and configuring processes such that the resulting capabilities maximize NPV.`, cls: 'Class 1 · Foundations' },
    { term: 'Operations Management (OM)', def: `Day-to-day management and improvement of activities in the transformation process (tactics).`, cls: 'Class 1 · Foundations' },
    { term: 'Process View', def: `Looking at operations through the lens of the transformation process / activity network — focuses on how work or activity is done.`, cls: 'Class 1 · Foundations' },
    { term: 'Resource View', def: `Looking at operations through the lens of the assets used in the transformation process — asks who or what does the activities/work.`, cls: 'Class 1 · Foundations' },
    { term: 'Competency / Capability View', def: `Looking at operations through the lens of what operations can and cannot do; asks which capabilities should an operation have, and connects directly to business strategy.`, cls: 'Class 1 · Foundations' },
    { term: 'Activity Network', def: `The set of activities and their connections that transform inputs into outputs.`, cls: 'Class 1 · Foundations' },
    { term: 'Asset Bundle', def: `The collection of real assets/resources used to perform activities.`, cls: 'Class 1 · Foundations' },
    { term: 'Alignment', def: `The principle that operations capabilities must be connected to the competitive position defined by business strategy. Operations strategy should develop resources and configure processes such that the resulting capabilities are connected or aligned with the competitive position that a firm seeks over time.`, cls: 'Class 1 · Foundations' },
    { term: 'Strategic Operational Audit (SOA)', def: `A diagnostic tool that identifies gaps between value proposition, competencies, and resources/processes. It examines three potential gaps: Strategy Gap (between what the firm promises and what it delivers), Competency Gap (between current and needed competencies), and Resource & Process Gap (between current and needed resources/processes).`, cls: 'Class 1 · Foundations' },
    { term: 'Product-Process Matrix (PPM / OMM)', def: `A tool that maps process flexibility against product variety to identify alignment. The alignment zone runs diagonally from bottom-left (standardized products, repetitive line, low flexibility) to top-right (customized solutions, job shop, high flexibility). Firms off the diagonal are misaligned.`, cls: 'Class 1 · Foundations' },
    { term: 'NPV (Net Present Value)', def: `Financial metric: NPV = C_0 + PV, where PV = sum of [C_t / (1+r)^t] for t = 1 to T. C_0 is the initial investment cost, C_t is the return cash flow in period t, and r is the discount rate. Used to evaluate strategic investments; the goal of operations strategy is to maximize NPV.`, cls: 'Class 1 · Foundations' },
    { term: 'Discount Rate (r)', def: `The rate of return used to discount future cash flows to present value; reflects the opportunity cost of capital and the risk of the investment.`, cls: 'Class 1 · Foundations' },
    { term: 'Vertical Integration', def: `A firm performing multiple stages of the supply chain internally rather than outsourcing.`, cls: 'Class 1 · Foundations' },
    { term: 'Job Shop', def: `A process type with high flexibility where each job follows a different path through the facility; suited for customized products.`, cls: 'Class 1 · Foundations' },
    { term: 'Batch Production', def: `A process type where products are made in groups/batches of a certain quantity; intermediate flexibility and cost.`, cls: 'Class 1 · Foundations' },
    { term: 'Repetitive / Line Production', def: `A process type with continuous flow of identical products; low flexibility, high efficiency.`, cls: 'Class 1 · Foundations' },
    { term: 'Continuous Production', def: `Uninterrupted process flow with no changeovers (e.g., petroleum processing); the most standardized, lowest-flexibility process type.`, cls: 'Class 1 · Foundations' },
    { term: 'Revenue Management (RM)', def: `The collection of demand management practices that aim to maximize the revenue of especially limited and perishable available supply.`, cls: 'Class 1 · Foundations' },
    { term: 'Marginal Analysis', def: `Analytical tool used to determine the optimal capacity size by setting marginal cost equal to marginal value; also used in revenue management to decide whether to accept or deny a demand request.`, cls: 'Class 1 · Foundations' },
    { term: 'Kaizen', def: `Japanese philosophy of continuous improvement — small, steady, incremental changes to processes made by all employees.`, cls: 'Class 1 · Foundations' },
    { term: 'Learning Curve', def: `The relationship between cumulative production experience and cost/efficiency improvements; empirically shows that costs decline by a consistent percentage each time cumulative volume doubles.`, cls: 'Class 1 · Foundations' },
    { term: 'Four OS Capability Dimensions', def: `The four key capabilities that operations strategy must build: Cost (total cost of operating), Quality (ability to deliver quality outputs), Lead-Time / Responsiveness (total responsiveness), and Flexibility (ability to change — scope, agility, robustness).`, cls: 'Class 1 · Foundations' },
  ],

  c2: [
    { term: 'Operational Trade-off', def: `A trade-off is "a balancing of factors all of which are not attainable at the same time; a giving up of one thing in return for another." Operational capabilities (Cost, Quality, Lead Time, Flexibility) are governed by trade-offs that are defined by the resources and the processes — the operational systems.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Trade-off Curve', def: `The graphical representation of the trade-offs inherent in an operational system. Each process type (job shop, batch, repetitive line) traces its own curve, showing the combinations of unit cost and non-cost capability (e.g., variety/flexibility) that the system can deliver.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Efficient Frontier', def: `A snapshot that traces the industry's lowest costs to produce specific non-cost-based capability bundles (e.g., quality, lead time, and flexibility). It is formed by the envelope (outer boundary) of all individual operational systems' trade-off curves in the industry. Points inside the frontier are attainable but inefficient; points outside are not currently attainable.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Sweet Spot', def: `An area on an operational system's trade-off curve where it operates on the efficient frontier. Outside this sweet spot, the system is less efficient relative to alternatives.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Operational Efficiency (OE)', def: `A non-cost-based capability's operational efficiency (OE) is measured by its cost disadvantage relative to the efficient frontier for that same capability.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'COE (Operational Efficiency Cost Differential)', def: `The largest cost advantage any competitor would have over us, were they to use their operational systems to deliver the same (non-cost) capabilities as we do. COE measures how much more efficiently a rival's operational system can deliver the same value proposition. A positive COE means we are operationally inefficient.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Delta C (Total Cost Difference)', def: `The raw, unadjusted cost difference between two firms — calculated by comparing costs at current operating conditions. NOT the meaningful number for threat assessment on its own; must be decomposed into Cv, COE, and CS.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Cv (Volume / Utilization Cost Differential)', def: `The extra costs incurred by operating at less than the strategically-targeted utilization level. Caused by economic downturns, market misses, or demand declines because fixed costs are spread over fewer units than planned. Calculated as: Actual cost per unit minus cost per unit at planned utilization.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'CS (Competitive Strategy-Driven Cost Differential)', def: `The cost difference inherent in the way each company chooses to compete. A strategy emphasizing product innovation and customer responsiveness is expected to be more costly than a pure low-cost strategy. This is a "legitimate" cost difference reflecting a deliberate strategic choice, not inefficiency.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Cost Decomposition Formula', def: `COE = ΔC + Cv,rival − Cv,us − CS. The total observed cost difference (ΔC) is decomposed into: volume/utilization effects (Cv), competitive strategy effects (CS), and the true operational efficiency differential (COE). To estimate COE, you must control for location, volume, and strategy.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Operational Focus', def: `A focused operation is one whose required capabilities are restricted to a narrow set in the capability space of costs, quality, lead time, and flexibility. "Simplicity and repetition breeds competence" — focus leads to OE because practice perfects and no compromises are necessary in the design of the operational system.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'OE Improvement', def: `Moving the trade-off curve outwards (away from the origin), creating new strategic options: a firm can choose to increase differentiation OR improve cost-efficiency (or both). Example: reducing setup times shifts the curve outward.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Focus Factory', def: `An operational unit that is deliberately restricted to a narrow set of capability requirements (e.g., one product family or one customer segment), enabling deeper expertise and better alignment between operational system and value proposition.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: '"Divide and Conquer" Approach to Focus', def: `Step 1: Partition products/services into groups with homogeneous capability needs. Step 2: For each group, separate those resources and processes that critically support its key value proposition while sharing the others. Step 3: Create a charter for each operation to retain focus over time.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'ACC (American Connector Company)', def: `Case company operating a batch-process plant in Sunnyvale, CA producing ~4,500 SKUs. Competes on design flexibility and customer solutions. Had effective utilization of only 30.2% and 26,000 defects per million units.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'DJC Corporation', def: `Japanese connector manufacturer operating a highly focused repetitive-line plant in Kawasaki producing ~640 SKUs. Vision: 100% asset utilization, 99% material yield, fewer than 1 defect per million units. Had effective utilization of 75.4%.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
    { term: 'Iso-NPV Curve', def: `A trade-off curve showing capability combinations that yield a given NPV (also called indifference curves for the same NPV). Used to represent the trade-offs inherent in choosing a competitive position on the efficient frontier.`, cls: 'Class 2 · Trade-offs & Competitive Positioning' },
  ],

  c3: [
    { term: 'Capacity Strategy', def: `The long-term plan for developing resources that involves decisions on size, timing, type, and location of real assets (from the OS Framework).`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Capacity Size', def: `Deciding the capacity investment level. All resources are limited by their capacity size, which typically represents the maximal sustainable output rate of that resource.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Capacity Timing', def: `The timing of capacity size adjustments. There is some leeway about the timing or dynamics of the investment.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Utilization', def: `Utilization = Flow Rate / Capacity, where Flow Rate is the real production output. Represents the fraction of capacity that is actually used.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Demand Chasing Strategy', def: `A capacity strategy where capacity closely tracks actual demand; adjustments are made frequently to match the demand level.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Leading Capacity Strategy', def: `A capacity strategy where capacity is added before demand materializes, creating excess capacity in the short run and building inventory to fill future demand. Risk: demand may not materialize as expected.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Lagging Capacity Strategy', def: `A capacity strategy where capacity is added after demand has increased, resulting in capacity shortages in the short run that create waiting lists or lost sales. Lower risk of excess capacity.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Hybrid Capacity Strategy', def: `A capacity strategy that combines elements of leading and lagging; periods of inventory buildup alternate with capacity shortage periods.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Follow-Your-Competitor Strategy', def: `A capacity strategy where a firm matches capacity additions to competitors' actions.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Economies of Scale (EOS)', def: `"Bigger is Better" — the cost of doubling the size is less than double the cost of the original size. Formally: C(2K) < 2C(K). Captured by the Power CapEx model: C(K) = c_0 + (c_K/alpha) × K^alpha, where 0 < alpha < 1.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Linear CapEx Model', def: `C(K) = c_0 + c_K × K, where c_0 is the fixed capacity investment cost (intercept) and c_K is the marginal capacity investment cost (slope). Assumes constant marginal cost — no economies of scale beyond the fixed cost.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Power CapEx Model', def: `C(K) = c_0 + (c_K / alpha) × K^alpha, where 0 < alpha < 1 allows for decreasing marginal cost (economies of scale). When alpha = 0.6 (typical), the cost curve is concave. When alpha = 1, this reduces to the linear model.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Capacity-Inventory-Waiting Triangle', def: `A fundamental framework showing three ways to handle the mismatch between capacity and demand: (1) Make resources wait — invest in safety/excess capacity; (2) Make products wait — build inventory to buffer demand fluctuations; (3) Make customers wait — let customers queue when demand exceeds capacity. The optimal position depends on relative costs.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Critical Ratio (Capacity)', def: `The expression (m + c_p − c_K) / (m + c_p) used to determine optimal capacity size. m = unit operating profit margin, c_p = unit penalty cost for unmet demand, c_K = marginal capacity investment cost. If CR > 50%, invest in safety capacity; if CR < 50%, scale down below average demand.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Optimal Capacity Size Formula', def: `Optimal K = F^{-1}((m + c_p − c_K) / (m + c_p)), where F is the cumulative demand distribution. For Normal demand D ~ N(μ, σ²): K = μ + z* × σ, where z* = NORM.S.INV((m + c_p − c_K) / (m + c_p)).`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Safety Capacity', def: `Excess capacity built above mean demand to buffer against demand uncertainty. For Normal demand, safety capacity = z* × σ. Optimal when the critical ratio > 50% (i.e., c_K is small relative to margins).`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Option Value of Waiting', def: `NPV(Wait) − NPV(Do Not Wait). The value of delaying a capacity decision to gather more information about demand. Waiting is valuable when uncertainty can be reduced substantially during the waiting period AND the investment opportunity does not disappear.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Strategic Timing', def: `Deals with the essential question: Should we adjust the capacity size now or should we wait? Captures key capacity investment drivers (EOS and uncertainty) over longer time frames. Tool: Option Value of Waiting = NPV(wait) − NPV(do not wait).`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Tactical Timing (Aggregate Planning)', def: `Deciding on tactical capacity adjustments: changing workers, hours, shifts, working days; building advance inventory; or maintaining waiting lists (back-orders) to accommodate temporary demand surges.`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Capacity Frictions', def: `Factors that make capacity adjustments difficult: lead-time (long lead times prevent leading strategies), lumpiness (capacity can only be added in discrete chunks), and fixed costs (substantial fixed costs create economies of scale).`, cls: 'Class 3 · Capacity: Size & Timing' },
    { term: 'Lumpiness', def: `The property that capacity can only be added in discrete chunks (not continuously), creating a minimum feasible capacity increment. This means small-volume products may incur disproportionately high per-unit costs in dedicated facilities.`, cls: 'Class 3 · Capacity: Size & Timing' },
  ],

  c4: [
    { term: 'Dedicated (Specialized) Capacity', def: `Capacity designed for a specific product or task. Benefit: efficiency and effectiveness — focus improves operational efficiency. Example: Ford's Model T assembly line. Lower construction cost per rig, higher yields, smoother operations.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Flexible (General-Purpose) Capacity', def: `Capacity that can handle many different products or tasks. Benefit: endless flexibility — can accommodate almost any new product without delay. More expensive per unit of output than dedicated capacity, but provides risk pooling, information updating, and flexibility allocation benefits.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Scope Flexibility', def: `Breadth of activities the plant can perform. Strategically aligned with strategies emphasizing variety and customization. Typically decreases with scale (bigger plants are harder to make flexible).`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Agility', def: `Speed of changeovers; could include scale flexibility. Strategically aligned with competing on speed and timeliness. Not correlated with scale.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Robustness', def: `Performance is uniform over the range of activities performed. Strategically aligned with strategies emphasizing cost and quality.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Risk Pooling (Flexibility)', def: `A source of flexibility value: pooling demand variability across products reduces total safety capacity needed. Pool standard deviation: σ_pool ≤ σ_1 + σ_2 (equality only when correlation = +1). Most effective when demand correlation is low or negative.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Information Updating', def: `A source of flexibility value: flexibility allows the delay of key decisions and the collection of more information. Related to the option value of waiting. Example: the flexible-then-specialized strategy in Eli Lilly — enables better go/no-go decisions and better sizing decisions for the specialized plant.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Flexibility Allocation', def: `A source of flexibility value that goes beyond risk pooling: if flexible capacity is insufficient to meet all demand, allocate it to the most profitable products first. Results in increased revenues (fewer losses) and reduced variance in profits.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Component Commonality (Universal Design)', def: `One component that can be used in multiple different models, allowing production of variety at lower cost, higher conformance quality, and faster response time. Reduces inventory complexity and enables risk pooling.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Modular Design', def: `Creating multiple versions of a component that all fit in multiple models, generating a multiplicative variety (e.g., 5 component versions × 5 models = 25 varieties) without large hits in other competencies (cost, quality, lead time).`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Postponement (Delayed Differentiation)', def: `A process design approach that combines product designs with common components and differentiator modules, and a process where differentiating elements are added at the end. Reduces time between product specification and delivery. Advantage: demand pooling for the common component; short lead times for variety.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Resource Chaining', def: `Capacity flexibility achieved through sharing and substitution in process design. A chain is a group of plants and products connected via links. Flexibility is more effective through long chains than through short chains or isolated links. Key principle: "A little flexibility goes a long way."`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: '"A Little Flexibility Goes a Long Way"', def: `The principle that a long chain configuration with only 20 links (each plant making 2 vehicles) can produce nearly the results of total flexibility (100 links in a 10-plant, 10-vehicle system). Simulation shows long chain / full flexibility ratio of 89–96%. Flexibility exhibits decreasing returns, so full flexibility is rarely worth its cost.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Mass Customization', def: `Tailors a product or service to each customer's wishes within certain limits, and produces and delivers it with a flexible flow process with negligible changeovers. Achieves high variety at low cost — the best of both worlds. Requires MTO/ATO for the last process step and postponement of differentiation fan-out.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Facility Substitution', def: `A process design approach with one flexible asset and one dedicated asset, where the flexible asset can serve as a backup for the dedicated asset's demand. Key insight: combines pooling power of flexible capacity with lower investment cost of dedicated capacity.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: 'Transshipment', def: `Relocating assets or inventory between locations to balance supply and demand across the network.`, cls: 'Class 4 · Capacity: Flexibility' },
    { term: '"Flexible Then Specialized" Transfer Strategy', def: `A hybrid approach using a flexible plant as a launch plant for the first 2–3 years, then transferring products to specialized plants as demand increases. Captures flexibility benefits (risk reduction, speed to market, information updating) while retaining the efficiency of specialized capacity at scale.`, cls: 'Class 4 · Capacity: Flexibility' },
  ],

  c5: [
    { term: 'Total Landed Cost (TLC)', def: `The total end-to-end cost to transform inputs at the sourcing location to outputs at customer locations. The scope of TLC analysis covers all combinations of products and customers. TLC has a cost focus — it requires carefully tracking direct and indirect (often hidden) costs through the entire value chain. A good TLC analysis can save approximately 5% on COGS.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Geographic / Spatial Analysis', def: `An analysis that starts with estimates of market demand per region and of the number of needed potential facilities, and ends by comparing all potential sites' Total Landed Costs (TLC). Used when transportation costs constitute a significant fraction of total costs (e.g., cement, insulation, fresh food).`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Network Analysis', def: `Analysis of the entirety of a company's facility locations and interconnections, capturing interdependencies with size and timing. The optimal location for the first plant depends on long-term network expansion plans; myopic decisions can lead to suboptimal networks.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Competitive Analysis (Location)', def: `Location analysis that takes competitors' locations and potential reactions into account. Especially important when customers' choice is based on proximity.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Hotelling Model', def: `A game-theoretic model (Harold Hotelling, 1929) predicting that under certain conditions, competing firms will tend to co-locate at the center of a market to maximize their share. Explains why competitors (e.g., car dealers) often cluster side by side.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Facility Role / Focus Analysis', def: `The process of specifying the strategic role, activities, responsibilities, and competences of each specific site in the network. Each facility must be assigned activities and responsibilities — it is not enough to say what a plant does; you must also specify what authority and capabilities it has.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Ferdows\' Strategic Role Matrix', def: `A 2×3 framework (Ferdows, 1997) classifying facility roles by primary strategic reason (access to low-cost production | skills & knowledge | market) and scope of activities (narrow & low vs. broad & high). Six roles: Offshore, Outpost, Server (narrow scope); Source, Lead, Contributor (broad scope). Plants can evolve from lower to higher roles.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Offshore Plant', def: `Produces specific items at low cost and exports them for further work or for sale. Has minimal authority and investment. This is the simplest, lowest-autonomy facility role (access to low-cost production, narrow scope).`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Source Plant', def: `Produces at low cost but with the same ability as the best plant in the network. Has authority over procurement, production, planning, logistics, process and product customization. A high-capability, low-cost plant (access to low-cost production, broad scope).`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Outpost Plant', def: `Primary role is to collect information from advanced suppliers, competitors, research labs, or customers — acts as a "listening post" or intelligence-gathering facility. Secondary role may be as an offshore or server plant. (Access to skills and knowledge, narrow scope.)`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Lead Plant', def: `Global hub for product and process knowledge and innovation. Has full authority over all activities. Taps into local skills and knowledge to initiate company-wide innovation. This is the highest-autonomy, most strategically important facility role. (Access to skills and knowledge, broad scope.)`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Server Plant', def: `Serves a specific regional market to overcome tariffs, taxes, logistics barriers, or foreign-exchange risk. Has limited authority to make minor modifications to fit local conditions. (Access to market, narrow scope.)`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Contributor Plant', def: `Serves a specific regional market but also competes with other plants in the network for new processes or products. Has authority over product and process development as well as supplier choice. A market-serving plant that also contributes to the network\'s innovation. (Access to market, broad scope.)`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Centralized Network', def: `A network with few, large facilities serving broad geographic areas. Offers economies of scale and risk pooling benefits but incurs higher transportation costs and lead times, and may lose local responsiveness.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Distributed Network', def: `A network with many facilities, each serving a local or regional area. Offers customer proximity but may sacrifice economies of scale and risk pooling.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Standardization (Network)', def: `Making facilities, processes, and equipment uniform across the network. Offers purchasing power, consistent quality, and facilitates integration and risk pooling. But can slow down improvements by inhibiting natural experimentation at individual plants.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Localization (Network)', def: `Adapting facilities, processes, or products to local conditions, inputs, or customer preferences. May be required by regulation or useful to exploit local inputs/suppliers. Can be part of a differentiation strategy.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Integration (Network)', def: `Designing facilities so that one location can serve multiple markets, or multiple locations can serve one market. Offers scale economies of capacity pooling. Becomes more valuable when demands and exchange rates become more volatile.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Separation (Network)', def: `Each facility serves its own local market with no cross-serving. Leads to market-focused plants with operational efficiencies and plant networks that are easy to manage.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Customer Proximity Premium', def: `The extra value customers place on being served from a nearby location (freshness, speed, local trust). This premium can justify the cost of a distributed network.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Economies of Scope', def: `Cost advantages from producing multiple products at a single facility. A location driver that, together with economies of scale, favors centralization.`, cls: 'Class 5 · Capacity: Location' },
    { term: 'Six Location Drivers', def: `The six categories that determine where a firm should locate capacity: (1) Competitive Strategy, (2) Product Markets (demand growth, customer proximity), (3) Supply Markets (input availability and costs), (4) Technology (scale economies, transportation costs), (5) Macro-Economic & Non-Market Factors (tariffs, taxes, exchange rates, IP, political stability), (6) Existing Resources and Processes.`, cls: 'Class 5 · Capacity: Location' },
  ],

  c6: [
    { term: 'Demand Management', def: `All activities that influence the demand for products and services, including marketing, sales, and operations-driven practices. Operations contributes by tailoring processes to demand characteristics to maximize NPV.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Revenue Management (RM)', def: `The collection of demand management practices that aim to maximize the revenue of available supply. Integrated with operations strategy through a three-step process: evaluate customer valuations → forecast demand and price products → control capacity allocation.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Price Controls', def: `RM techniques that vary prices to influence demand. Includes price customization (segmenting customers by WTP) and dynamic pricing (markdowns, promotions, peak-load pricing).`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Capacity Controls', def: `RM techniques that restrict available supply to influence demand. Includes yield management (reservation systems: booking limits, protection levels) and overbooking (accepting more reservations than physical capacity to account for no-shows) and service customization.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'WTP (Willingness to Pay)', def: `The maximum price a customer is willing to pay for a product or service. Also called "reservation price." Usually unobservable directly, so firms use self-selection mechanisms (features and fences) to partially reveal it.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: '1st Degree Price Discrimination', def: `Perfectly discriminating (sorting) customers based on their WTP and charging each customer exactly their WTP. Ideal but usually unachievable because a customer\'s WTP is usually unobservable.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: '2nd Degree Price Discrimination', def: `Designing differentiated "products" according to a set of features and fences, and letting customers self-select (choose), thereby partially revealing their WTP. The key principle: match product features to customer preferences and WTP. Also called customer segmentation.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Fare Class', def: `A "product" defined by a combination of price and restrictions (e.g., Class Q, E, G in the airline industry). Each fare class represents a different combination of price and features/fences designed to sort customers by WTP.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Customer Segmentation', def: `Dividing customers into groups with similar WTP to enable charging different prices. Requires: valuations vary considerably over customers, customers can be efficiently sorted, and each segment\'s valuation can be forecasted with reasonable accuracy.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Capacity Segmentation', def: `The operational counterpart of customer segmentation — segmenting the same physical capacity (e.g., economy cabin) into different buckets (fare classes) for different customer segments. Combined with capacity allocation: deciding how much capacity to reserve for each segment.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Protection Level', def: `The number of capacity units reserved (protected) for a higher-fare class against demand from a lower-fare class. Booking limit = Total capacity − Protection level.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Booking Limit', def: `The maximum number of units available for sale to a particular fare class. Booking Limit = Total Capacity − Protection Level.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Displacement Cost', def: `The opportunity cost of accepting a low-fare request — the expected revenue that could be earned by selling that unit of capacity to a future, higher-paying customer. Decision rule: Accept a request if Revenue > Displacement Cost.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Littlewood\'s Rule', def: `The optimal two-class protection level Q satisfies: Prob(D_high ≤ Q) = (p_high − p_low) / p_high. Formula: Q = NORMINV((p_high − p_low) / p_high, mean_D_high, sd_D_high). Logic: deny advance booking at the low fare if the expected revenue from a future high-fare sale exceeds the certain low-fare revenue.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Overbooking', def: `Accepting more reservations than physical capacity to account for expected no-shows. Marginal analysis: overbook one more slot as long as P(no-shows ≥ current level) > Cost_overbook / (Cost_overbook + Revenue_per_seat).`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Dynamic Pricing', def: `Changing prices over time in response to demand conditions. Includes: markdowns (reducing price over time to clear inventory), promotions (temporary price reductions to stimulate demand), and peak-load pricing (charging higher prices during peak demand periods).`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Yield Management', def: `Allocating limited capacity to different customer segments or fare classes to maximize total revenue. Includes reservation systems (booking limits and protection levels) and overbooking.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Perishable Product', def: `A product or capacity unit whose revenue opportunity is lost if not used within a specific time window. An empty airline seat on a departed flight or an unused hotel room — the revenue opportunity is lost forever.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Three Conditions for RM', def: `Revenue management is most valuable when: (1) Supply is constrained and perishable — limited supply and finite sales window; (2) Demand is dynamic and volatile — pricing decisions must be made before demand uncertainty is resolved; (3) Customer segmentation is possible — valuations vary considerably, sorting variables exist, and segment valuations can be forecasted.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Strategic Sourcing', def: `Deciding on appropriate supply relationships for each and every activity in the value chain. Typically involves: identifying the activity and potential suppliers, the make-or-buy decision, and defining/establishing/managing the bilateral relationship.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'TCO (Total Cost of Ownership)', def: `Total cost of sourcing from a supplier or of using any activity provided by a given supplier. Goes beyond the purchase price to include all costs associated with the supplier relationship. Calculated via three steps: (1) determine all impacted activities, (2) identify cost drivers using activity-based costing, (3) sum all costs per supplier.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Make-or-Buy Decision', def: `The decision whether to produce an activity internally (vertical integration) or outsource it. Evaluated using TCO and NPV analysis, considering feasibility, necessity, strategic alignment, supplier capability, and ability to manage the relationship.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Market Buy', def: `External sourcing through transactional market exchanges. Benefits: focus on core activities, access to suppliers with lower costs or latest innovation, risk transfer, and flexibility to switch suppliers or scale up/down.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Vertical Integration (Sourcing)', def: `Owning and controlling successive stages of the value chain internally. Benefits: full control over quality/timing/processes, aligned incentives (no misalignment between stages), learning by doing, and protection of proprietary assets.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Tailored Sourcing', def: `Using different sourcing strategies for different portions of demand or different product types. Example: use a cost-efficient but less flexible supplier for base demand, and a responsive supplier for volatile demand.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Multi-Sourcing', def: `Using multiple suppliers for a given input. Benefits: reduces supply disruption risk, provides assurance of supply, avoids supplier dependence, maintains competition among suppliers, and allows testing of new suppliers.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Single Sourcing', def: `Using one supplier for a given input. Benefits: may qualify for volume discounts, makes the buyer a more important customer, simpler to manage, and is prerequisite to deep partnering relationships.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Quantity Discount Contract', def: `A contract offering lower per-unit prices for higher order quantities. Three types: all-unit quantity discount (discount applies to ALL units if order exceeds threshold), incremental quantity discount (discount applies only to units above the threshold), and cumulative/volume discount (based on total purchases over a period).`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Quantity Flexibility Contract', def: `A contract where the buyer commits to a certain percentage of forecasted quantity before demand is known, and in return the supplier invests in extra capacity to anticipate possible higher demand. Shares demand risk between buyer and supplier.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Buy-Back Contract', def: `A contract where the supplier agrees to buy back unsold units from the buyer at a pre-agreed price. Reduces the buyer\'s risk of overstocking and incentivizes the buyer to order more aggressively.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Revenue Sharing Contract', def: `A contract where the buyer pays a lower wholesale price but shares a percentage of revenue with the supplier. Aligns the incentives of buyer and supplier: both benefit when products sell well. Example: Blockbuster and movie studios.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Options Contract', def: `A contract where the buyer purchases options (the right but not the obligation) to buy units at a pre-agreed price in the future. The buyer pays an upfront premium per option. Gives the buyer flexibility while compensating the supplier for reserving capacity.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Five-Question Sourcing Framework', def: `A structured decision process for outsourcing: Q1: Is outsourcing feasible (stable supply base, politically viable)? Q2: Is outsourcing necessary (internal capabilities insufficient)? Q3: Is it strategically aligned and risks tolerable? Q4: Can external suppliers do it better (TCO/NPV analysis)? Q5: Can we manage suppliers? → Easy: Market Buy; Difficult: Long-Term Relationship; Impossible: Vertical Integration.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Modular Technology', def: `Product architecture with standardized interfaces that allows independent design and production of components. Makes outsourcing more attractive because components can be sourced separately without deep integration between buyer and supplier.`, cls: 'Class 6 · Supply & Demand Management' },
    { term: 'Newsvendor Model (Applied to Capacity)', def: `A marginal analysis framework applied to capacity reservation: the "overage cost" (Co) is the profit foregone from a contract rejected to hold floating capacity; the "underage cost" (Cu) is the extra profit that could have been earned from floating demand. Critical ratio = Cu / (Cu + Co). Optimal floating capacity = NORMINV(CR, mean, sd).`, cls: 'Class 6 · Supply & Demand Management' },
  ],

  c7: [
    { term: 'Product Technology', def: `The scientific and technical knowledge embedded in the products themselves. Examples: transistors, flash memory chips, electron microscopes. Must be linked with process technology — the product IS often defined by how it is made.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Process Technology', def: `The technology used in manufacturing, transportation, and coordination of operations. Three categories: manufacturing technology (equipment and methods to make products), transportation technology (how goods move), and coordination technology (how activities are synchronized and managed).`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Concurrent (Simultaneous) Engineering', def: `Developing product and process in parallel rather than sequentially. Reduces time to market, improves manufacturability, and ensures the production process is designed alongside the product rather than after it.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Design for Manufacturing (DFM)', def: `Product design rules that make manufacturing easier and more efficient. Part of linking product technology and process development — reduces costs, improves yield, and improves conformance quality.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Innovation', def: `Creating something new. Can be both significant and incremental; may or may not accumulate to radical change. Building capabilities for innovation must be an integral part of the theory and practice of operations strategy.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Improvement', def: `Making something better. Can be both radical (reengineering) and continuous (Lean and Six Sigma). The fundamental question in operations strategy is how to stay ahead and adapt competencies to changing customer preferences.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Continuous Improvement (CI)', def: `Seeking steady, incremental change through low-risk projects. Four guiding principles: (1) scientific method — test before implementing; (2) reduce process variability — all work highly specified; (3) employee empowerment — all employees make improvements, managers coach; (4) built-in tests (controls) — activities and flow paths have built-in signals for problems.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Reengineering', def: `Fundamental rethinking and radical redesign of business processes to achieve breakthrough, superior performance with a new, unproven process. High-risk, large projects. Guidelines: identify knowledge gaps proactively, use a stage-gate process (Feasibility → Prototype → Pilot → Full-Scale), use simulation, use partners/contractors to manage risk.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Lean', def: `A systematic method for waste minimization — seeks to eliminate all non-value-adding activities (deviations from the ideal, perfectly synchronized, lowest-cost operation). Rooted in the Toyota Production System. A form of continuous improvement.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Six Sigma', def: `A quality management methodology aiming for near-zero defects by reducing process variability. A form of continuous improvement focused on variability reduction using statistical methods.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Conceptual Learning', def: `Understanding the "why" behind processes — the scientific and theoretical understanding. Unleashes the power of science and technology to improve. Compatible with step change and drastic improvement; encourages a safe and efficient organization that promotes knowledge sharing.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Operational Learning', def: `Understanding the "how" of executing processes. Unleashes the creativity of the whole workforce and its power to improve. Compatible with continuous improvement; essential to Toyota\'s Kaizen system. Encourages a dynamic organization that minimizes planning time.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Learning Before Doing', def: `Learning that occurs through experiments, simulations, and pilot studies BEFORE full-scale production. Timing of transfer to full-scale depends on: depth of process knowledge, fidelity of experiments, and cost of experiments vs. full-scale trials.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Learning By Doing', def: `Learning that occurs on the production floor through actual experience. People engaged in repetitive tasks learn by doing — captured empirically by the learning curve. Cumulative volume drives learning; each unit processed adds to organizational knowledge.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Learning Curve', def: `An empirical observation showing that the amount of direct labor hours needed for one unit of production reduces by a similar percentage every time cumulative volume doubles. Mathematical form: C(Q) = C_1 × Q^(−β), where C_1 is the marginal cost of the first unit and β is the learning exponent (slope on a log-log scale).`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Learning Rate', def: `The percentage by which unit cost decreases each time cumulative volume doubles. Learning rate = 1 − 2^(−β). For semiconductors (1974–1998), β ≈ 3/7, giving a learning rate of approximately 25.7% per doubling.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'β (Learning Exponent)', def: `The slope of the learning curve measured on a log-log scale. Appears in the power form: C(Q) = C_1 × Q^(−β). A higher β means faster learning. The learning rate = 1 − 2^(−β).`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Moore\'s Law', def: `The empirical observation (Gordon Moore, 1964) that the number of transistors in a dense integrated circuit doubles about every two years. NOT a law of physics but an empirical relationship linked to gains from experience in production — essentially a learning curve for semiconductors.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Product-Process Life Cycle', def: `As a product matures through its technology life cycle, the process technology should evolve accordingly. Early stage (high demand variability): process should have flexibility to allow product innovation. Later stage (product design stabilizes): invest in automation to reduce costs. Less flexible, but product designs have stabilized so this is acceptable.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Platform Strategy', def: `Treating a core technology (e.g., mRNA) as a platform like an operating system, on which multiple different products ("apps") can be built with shared learning. Allows developing multiple medicines in parallel with learnings from one drug spilling over directly into others. Contrasts with traditional one-product-at-a-time approaches.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Copy Best Practice', def: `A medium-risk improvement strategy for replicating an active best practice representing a large, breakthrough improvement. Guidelines: ensure the system can be copied and is worth copying; work from a single, active template; copy as closely and completely as possible; don\'t adapt until reaching acceptable results; when problems occur, refer back to the active template.`, cls: 'Class 7 · Technology & Innovation' },
    { term: 'Stage-Gate Process', def: `A structured approach for reengineering projects to start small and reduce risk before committing large resources: Feasibility Studies → Product Prototype → Pilot Plant → Full-Scale Plant. Each gate is a go/no-go decision point before advancing to the next stage.`, cls: 'Class 7 · Technology & Innovation' },
  ],
};
